const stytch = require('stytch');

const client = new stytch.Client({
  project_id: process.env.STYTCH_PROJECT_ID,
  secret: process.env.STYTCH_SECRET,
  env: stytch.envs.test, // Defaulting to test environment
});

const user_id = process.argv[2];

if (!user_id) {
  console.error('Please provide a user_id as the first command-line argument.');
  process.exit(1);
}

async function registerPasskey() {
  try {
    const response = await client.webauthn.registerStart({
      user_id: user_id,
      domain: 'example.com',
      return_passkey_credential_options: true,
    });

    if (response.public_key_credential_creation_options) {
      console.log(JSON.stringify(response.public_key_credential_creation_options, null, 2));
    } else {
      console.error('No public_key_credential_creation_options found in the response.');
      process.exit(1);
    }
  } catch (error) {
    console.error('Error starting WebAuthn registration:', error);
    process.exit(1);
  }
}

registerPasskey();

